                        KEY_LENGTH, KEY_LENGTH * 2, keyBytes.length));
            }

            // Generate random IV (nonce) for this encryption operation
            // Using SecureRandom for cryptographically secure random numbers
            byte[] iv = new byte[GCM_IV_LENGTH];
            SecureRandom secureRandom = new SecureRandom();
            secureRandom.nextBytes(iv);

            // Initialize cipher for encryption
            SecretKeySpec secretKey = new SecretKeySpec(keyBytes, ALGORITHM);
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);

            // GCMParameterSpec with IV and authentication tag length
            GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey, gcmSpec);

            // Perform encryption
            byte[] ciphertext = cipher.doFinal(data);

            // Combine IV + ciphertext (which includes auth tag in GCM mode)
            // In Java's GCM implementation, doFinal returns ciphertext + auth tag
            byte[] encryptedData = new byte[iv.length + ciphertext.length];
            System.arraycopy(iv, 0, encryptedData, 0, iv.length);
            System.arraycopy(ciphertext, 0, encryptedData, iv.length, ciphertext.length);

            // Return as hexadecimal string
            return bytesToHex(encryptedData);

        } catch (IllegalArgumentException e) {
            throw e; // Re-throw validation exceptions
        } catch (Exception e) {
            // Wrap cryptographic exceptions in runtime exception
            throw new RuntimeException("Encryption failed: " + e.getMessage(), e);
        }
    }

    /**
     * Converts a hexadecimal string to a byte array.
     * 
     * @param hex The hexadecimal string to convert
     * @return The byte array representation
     * @throws IllegalArgumentException if hex string is invalid
     */
    private static byte[] hexToBytes(String hex) {
        if (hex == null) {
            throw new IllegalArgumentException("Hex string cannot be null");
        }

        int len = hex.length();
        if (len % 2 != 0) {
            throw new IllegalArgumentException("Hex string must have even length");
        }

        // Check for valid hex characters
        if (!hex.matches("[0-9A-Fa-f]+")) {
            throw new IllegalArgumentException("Hex string contains invalid characters");
        }

        byte[] data = new byte[len / 2];
        for (int i = 0; i < len; i += 2) {
            data[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4)
                                + Character.digit(hex.charAt(i + 1), 16));
        }
        return data;
    }

    /**
     * Converts a byte array to a hexadecimal string.
     * 
     * @param bytes The byte array to convert
     * @return Lowercase hexadecimal string representation
     */
    private static String bytesToHex(byte[] bytes) {
        if (bytes == null) {
            return "";
        }

        StringBuilder sb = new StringBuilder(bytes.length * 2);
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    /**
     * Private constructor to prevent instantiation of utility class.
     */
    private AESService() {
        throw new AssertionError("Utility class should not be instantiated");
    }
}
